// Cada item de entrada = array de palpites de UM jogo
// allMatches[i] = dados do jogo i (placar real)
const allItems = $input.all();
const allMatches = $('Mapear e Filtrar Jogos').all();

function outcome(h, a) { return h > a ? 1 : h < a ? -1 : 0; }

const result = [];

for (let i = 0; i < allItems.length; i++) {
  const rawPreds = allItems[i].json;
  const preds = Array.isArray(rawPreds) ? rawPreds : [rawPreds];
  if (!preds.length || preds[0].id == null) continue;

  const matchData = allMatches[i] ? allMatches[i].json : null;
  if (!matchData || matchData.home_score == null) continue;

  const homeScore = matchData.home_score;
  const awayScore = matchData.away_score;
  const realOutcome = outcome(homeScore, awayScore);
  const realDiff = homeScore - awayScore;

  // Agrupar por tier: 1 PATCH por pontuação por jogo
  const groups = {};
  for (const p of preds) {
    const po = outcome(p.home_score, p.away_score);
    const pd = p.home_score - p.away_score;
    let pts;
    if (p.home_score === homeScore && p.away_score === awayScore) pts = 3;
    else if (po === realOutcome && realOutcome !== 0 && pd === realDiff) pts = 2;
    else if (po === realOutcome) pts = 1;
    else pts = 0;
    if (!groups[pts]) groups[pts] = [];
    groups[pts].push(p.id);
  }

  for (const [pts, ids] of Object.entries(groups)) {
    result.push({ json: { points: parseInt(pts), ids: ids.join(',') } });
  }
}

return result;
